from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)

# Set the client ID and secret for your OAuth 2.0 application
client_id = "your_client_id"
client_secret = "your_client_secret"

@app.route("/login")
def login():
    # Redirect users to the authorization server for login
    redirect_uri = f"{request.url}/callback"
    auth_url = f"https://auth.example.com/authorize?response_type=code&client_id={client_id}&redirect_uri={redirect_uri}"
    return redirect(auth_url)

@app.route("/callback")
def callback():
    # Exchange the authorization code for an access token using requests.post()
    auth_code = request.args.get("code")
    data = {
        "grant_type": "authorization_code",
        "client_id": client_id,
        "client_secret": client_secret,
        "redirect_uri": f"{request.url}/callback",
        "code": auth_code
    }
    response = requests.post("https://auth.example.com/token", data=data)
    access_token = response.json()["access_token"]
    
    # Store the access token in the session
    session["access_token"] = access_token
    
    return "Access token acquired"